/**
 * @summary Upload multiple product images
 */
export const getUploadImagesUrl = () => {
  return `/api/upload/images`;
};

export const uploadImages = async (
  uploadImagesBody: UploadImagesBody,
  options?: RequestInit,
): Promise<MultiUploadResponse> => {
  const formData = new FormData();
  if (uploadImagesBody.images !== undefined) {
    uploadImagesBody.images.forEach((value) =>
      formData.append(`images`, value),
    );
  }

  return customFetch<MultiUploadResponse>(getUploadImagesUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

